const KEY="algebraGlowUpDataV2";
const GENERATOR_VERSION=20;
let data=load(), exam=null, timerId=null;
const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
function defaultData(){return{profile:{},history:[],draft:null,generatorLog:{usedPromptKeys:[],usedPromptTexts:[],sessionCounter:0,topicCounters:{}}}}
function shapeData(saved){saved=saved||defaultData();saved.profile=saved.profile||{};saved.history=Array.isArray(saved.history)?saved.history:[];saved.generatorLog=saved.generatorLog||{};saved.generatorLog.usedPromptKeys=Array.isArray(saved.generatorLog.usedPromptKeys)?saved.generatorLog.usedPromptKeys:[];saved.generatorLog.usedPromptTexts=Array.isArray(saved.generatorLog.usedPromptTexts)?saved.generatorLog.usedPromptTexts:[];saved.generatorLog.sessionCounter=Number(saved.generatorLog.sessionCounter)||0;saved.generatorLog.topicCounters=saved.generatorLog.topicCounters&&typeof saved.generatorLog.topicCounters==="object"?saved.generatorLog.topicCounters:{};if(saved.draft&&saved.draft.generatorVersion!==GENERATOR_VERSION)saved.draft=null;return saved}
function load(){try{return shapeData(JSON.parse(localStorage.getItem(KEY))||defaultData())}catch{return defaultData()}}
function save(){localStorage.setItem(KEY,JSON.stringify(data))}
function normalize(v){return String(v??"").toLowerCase().replace(/\s/g,"").replace(/[âˆ’â€“]/g,"-").replace(/[â‚€-â‚‰]/g,c=>"â‚€â‚پâ‚‚â‚ƒâ‚„â‚…â‚†â‚‡â‚ˆâ‚‰".indexOf(c))}
function questionKey(q){return normalize(`${q.topic}|${q.prompt}`)}
function rememberQuestionSet(questions){data=shapeData(data);let keys=data.generatorLog.usedPromptKeys,texts=data.generatorLog.usedPromptTexts,seen=new Set(keys);questions.forEach(q=>{let key=questionKey(q);if(!seen.has(key)){keys.push(key);texts.push(`${q.topic}: ${q.prompt}`);seen.add(key)}});data.generatorLog.usedPromptKeys=keys.slice(-5000);data.generatorLog.usedPromptTexts=texts.slice(-500);save()}
function logFormKey(value){
  let s=String(value??"").toLowerCase().replace(/[â‚‚â‚ƒâ‚„â‚…â‚†â‚‡â‚ˆâ‚‰â‚€â‚پ]/g,c=>"â‚€â‚پâ‚‚â‚ƒâ‚„â‚…â‚†â‚‡â‚ˆâ‚‰".indexOf(c)).replace(/equals/g,"=").replace(/\s+/g," ").trim();
  let patterns=[
    /log\s*[_ ]?\s*(\d+)\s*\(?\s*(\d+)\s*\)?\s*=\s*(\d+)/,
    /log\s*base\s*(?:of\s*)?(\d+)\s*(?:of\s*)?(\d+)\s*=\s*(\d+)/,
    /log\s*(\d+)\s*(?:of\s*)?(\d+)\s*=\s*(\d+)/
  ];
  for(let p of patterns){let m=s.match(p);if(m)return `${m[1]}|${m[2]}|${m[3]}`}
  return "";
}
function isCorrect(q,a){let answers=Array.isArray(q.answer)?q.answer:[q.answer];if(q.topic==="Logarithms"){let userLog=logFormKey(a);if(userLog&&answers.some(x=>logFormKey(x)===userLog))return true}return answers.some(x=>normalize(x)===normalize(a))}
function uniqueChoices(answer,candidates){
  let choices=[],seen=new Set();
  [answer,...candidates,"None of these","Cannot be determined","No solution"].forEach(choice=>{
    let key=normalize(choice);
    if(choice!=null&&!seen.has(key)&&choices.length<4){choices.push(choice);seen.add(key)}
  });
  return shuffle(choices);
}
function shuffle(a){return [...a].sort(()=>Math.random()-.5)}
function grade(p){return p>=93?"A":p>=90?"Aâˆ’":p>=87?"B+":p>=83?"B":p>=80?"Bâˆ’":p>=77?"C+":p>=73?"C":p>=70?"Câˆ’":p>=60?"Needs review":"Reteach needed"}
function showView(name){$$(".view").forEach(v=>v.classList.add("hidden"));$(`#${name}View`).classList.remove("hidden");$$("[data-view]").forEach(b=>b.classList.toggle("active",b.dataset.view===name));if(name==="dashboard")renderDashboard();if(name==="admin")renderAdmin();if(name==="home")updateResumeButton();scrollTo(0,0)}
function updateResumeButton(){let b=$("#resumeExam");if(b)b.classList.toggle("hidden",!data.draft)}
function resumeExam(){if(!data.draft){toast("No saved test yet.");return}exam=data.draft;applyProfile();showView("exam");$("#examStudent").textContent=data.profile.voice==="bestie"?`${data.profile.name||"Bestie"}, let's finish this.`:`${data.profile.name||"Student"}'s saved exam`;renderQuestion();startTimer()}
const ADMIN_EMAILS=(window.APP_ADMIN_EMAILS||[]).map(e=>e.toLowerCase());
let fb=null,authUser=null,account=null,functionsApi=null,accountUnsub=null;
function firebaseConfigured(){return window.firebase&&window.FIREBASE_CONFIG&&!String(window.FIREBASE_CONFIG.apiKey||"").includes("PASTE_")}
function callFn(name,data={}){if(!functionsApi)throw new Error("Firebase Functions are not ready.");return functionsApi.httpsCallable(name)(data).then(r=>r.data)}
function showAuthMessage(msg){let el=$("#authMessage");if(el)el.textContent=msg}
function setAuthGate(show){let gate=$("#authGate");if(!gate)return;gate.classList.toggle("hidden",!show);gate.style.display=show?"grid":"none";gate.setAttribute("aria-hidden",show?"false":"true");$("#signOutButton")?.classList.toggle("hidden",show)}
function renderAccount(){let email=authUser?.email||"",isAdmin=ADMIN_EMAILS.includes(email.toLowerCase()),isPremium=account?.accountType==="premium"||account?.premiumStatus==="approved"||isAdmin;$("#adminNav")?.classList.toggle("hidden",!isAdmin);$("#accountBox")?.classList.toggle("hidden",!authUser);$("#accountEmail").textContent=email;$("#accountStatus").textContent=isPremium?"Premium account":"Basic account";$("#upgradePremium")?.classList.toggle("hidden",isPremium)}
function isPremiumAccount(){return account?.accountType==="premium"||account?.premiumStatus==="approved"||isAdminEmail(authUser?.email)}
function todayKey(){return new Date().toISOString().slice(0,10)}
function isAdminEmail(email){return ADMIN_EMAILS.includes(String(email||"").toLowerCase())}
async function firestoreSyncAccount(){let db=fb.firestore(),ref=db.collection("users").doc(authUser.uid),snap=await ref.get(),admin=isAdminEmail(authUser.email),now=firebase.firestore.FieldValue.serverTimestamp();if(!snap.exists){account={uid:authUser.uid,email:authUser.email,displayName:authUser.displayName||"",accountType:admin?"premium":"basic",premiumStatus:admin?"approved":"none",lastTestDate:"",testsToday:0};await ref.set({...account,createdAt:now,lastLoginAt:now})}else{account={uid:authUser.uid,...snap.data()};account={...account,email:authUser.email,displayName:authUser.displayName||"",accountType:admin?"premium":account.accountType||"basic",premiumStatus:admin?"approved":account.premiumStatus||"none"};await ref.set({email:account.email,displayName:account.displayName,lastLoginAt:now,accountType:account.accountType,premiumStatus:account.premiumStatus},{merge:true})}return account}
async function syncAccount(){try{let res=await callFn("syncUser");account=res.user;renderAccount();showAuthMessage("")}catch(e){try{account=await firestoreSyncAccount();renderAccount();showAuthMessage("")}catch(err){showAuthMessage(err.message||"Could not sync account.")}}}
async function clearOldAppCache(){try{if("serviceWorker"in navigator){let regs=await navigator.serviceWorker.getRegistrations();await Promise.all(regs.map(reg=>reg.unregister()))}if("caches"in window){let names=await caches.keys();await Promise.all(names.map(name=>caches.delete(name)))}}catch(e){}}
async function signInProvider(){if(!fb)return;try{showAuthMessage("Opening Google sign-in...");await clearOldAppCache();let provider=new firebase.auth.GoogleAuthProvider();provider.setCustomParameters({prompt:"select_account"});let result=await firebase.auth().signInWithPopup(provider);if(result?.user)await applySignedInUser(result.user)}catch(e){showAuthMessage(e.message||"Sign-in failed.")}}
async function initFirebaseAuth(){if(!firebaseConfigured()){setAuthGate(true);showAuthMessage("Firebase is not configured yet. Paste your Firebase config into firebase-config.js first.");return}firebase.initializeApp(window.FIREBASE_CONFIG);fb=firebase;functionsApi=firebase.functions();let handleUser=async user=>{authUser=user;if(!user){account=null;renderAccount();setAuthGate(true);return}setAuthGate(false);showAuthMessage(`Signed in as ${user.email||"your account"}. Loading your plan...`);await syncAccount()};firebase.auth().getRedirectResult().then(r=>{if(r?.user)handleUser(r.user)}).catch(e=>showAuthMessage(e.message||"Google sign-in could not finish."));firebase.auth().onAuthStateChanged(handleUser);let tries=0,check=setInterval(()=>{tries++;let user=firebase.auth().currentUser;if(user){clearInterval(check);handleUser(user)}else if(tries>20){clearInterval(check)}},250)}
async function canStartPractice(){if(!authUser){setAuthGate(true);toast("Please sign in first.");return false}try{await callFn("startTestSession");return true}catch(e){try{await syncAccount();let premium=account?.accountType==="premium"||account?.premiumStatus==="approved"||isAdminEmail(authUser.email),today=todayKey();if(!premium&&account?.lastTestDate===today&&(account?.testsToday||0)>=1){toast("Basic accounts can take one test per day. You can request premium for unlimited tests.");return false}let nextCount=account?.lastTestDate===today?(account?.testsToday||0)+1:1;await fb.firestore().collection("users").doc(authUser.uid).set({lastTestDate:today,testsToday:nextCount},{merge:true});account.lastTestDate=today;account.testsToday=nextCount;return true}catch(err){toast(err.message||"Could not check your account yet.");return false}}}
async function requestPremium(){try{let res=await callFn("requestPremium");toast(res.status==="already-premium"?"You are already premium.":"Premium request sent to admin.");await syncAccount()}catch(e){try{if(!authUser)return;await fb.firestore().collection("premiumRequests").doc(authUser.uid).set({uid:authUser.uid,email:authUser.email,displayName:authUser.displayName||"",status:"pending",createdAt:firebase.firestore.FieldValue.serverTimestamp()},{merge:true});await fb.firestore().collection("users").doc(authUser.uid).set({premiumStatus:"requested"},{merge:true});toast("Premium request sent to admin.");await syncAccount()}catch(err){toast(err.message||"Could not request premium.")}}}
