async function renderAdmin(){try{let data=await callFn("adminListDashboard"),usage=data.usage||[],users=data.users||[],requests=data.premiumRequests||[];$("#adminStats").innerHTML=stats([["Users",users.length],["Premium requests",requests.length],["Usage 24h",countUsage(usage,86400000)],["Usage 30d",countUsage(usage,2592000000)]]);$("#premiumRequests").innerHTML=requests.length?requests.map(r=>`<div class="history-row"><strong>${escapeHtml(r.email)}</strong><span>${escapeHtml(r.displayName||"")}</span><button class="soft" data-approve="${escapeHtml(r.uid)}">Approve</button></div>`).join(""):`<p class="fine-print">No pending requests.</p>`;$("#adminUsers").innerHTML=users.map(u=>`<div class="history-row"><strong>${escapeHtml(u.email||"")}</strong><span>${escapeHtml(u.accountType||"basic")} آ· ${escapeHtml(u.premiumStatus||"none")}</span><span>${u.lastLoginAt?.seconds?new Date(u.lastLoginAt.seconds*1000).toLocaleDateString():""}</span></div>`).join("");$$("[data-approve]").forEach(b=>b.onclick=async()=>{await callFn("adminSetPremium",{uid:b.dataset.approve,approved:true});toast("Premium approved.");renderAdmin()})}catch(e){$("#premiumRequests").innerHTML=`<p class="fine-print">${escapeHtml(e.message||"Admin data unavailable.")}</p>`}}
async function renderAdmin(){try{let data=await callFn("adminListDashboard"),usage=data.usage||[],users=data.users||[],requests=data.premiumRequests||[];renderAdminLists(users,requests,usage,async uid=>callFn("adminSetPremium",{uid,approved:true}))}catch(e){try{if(!isAdminEmail(authUser?.email))throw new Error("Admin only.");let db=fb.firestore(),usersSnap=await db.collection("users").get(),reqSnap=await db.collection("premiumRequests").get(),users=usersSnap.docs.map(d=>({uid:d.id,...d.data()})),requests=reqSnap.docs.map(d=>({uid:d.id,...d.data()}));renderAdminLists(users,requests,[],async uid=>{await db.collection("users").doc(uid).set({accountType:"premium",premiumStatus:"approved"},{merge:true});await db.collection("premiumRequests").doc(uid).delete()})}catch(err){$("#premiumRequests").innerHTML=`<p class="fine-print">${escapeHtml(err.message||"Admin data unavailable.")}</p>`}}}
function renderAdminLists(users,requests,usage,approve){$("#adminStats").innerHTML=stats([["Users",users.length],["Premium requests",requests.length],["Usage 24h",countUsage(usage,86400000)],["Usage 30d",countUsage(usage,2592000000)]]);$("#premiumRequests").innerHTML=requests.length?requests.map(r=>`<div class="history-row"><strong>${escapeHtml(r.email)}</strong><span>${escapeHtml(r.displayName||"")}</span><button class="soft" data-approve="${escapeHtml(r.uid)}">Approve</button></div>`).join(""):`<p class="fine-print">No pending requests.</p>`;$("#adminUsers").innerHTML=users.map(u=>`<div class="history-row"><strong>${escapeHtml(u.email||"")}</strong><span>${escapeHtml(u.accountType||"basic")} آ· ${escapeHtml(u.premiumStatus||"none")}</span><span>${u.lastLoginAt?.seconds?new Date(u.lastLoginAt.seconds*1000).toLocaleDateString():""}</span></div>`).join("");$$("[data-approve]").forEach(b=>b.onclick=async()=>{await approve(b.dataset.approve);toast("Premium approved.");renderAdmin()})}
