async function renderAdmin(){try{if(!isAdminEmail(authUser?.email))throw new Error("Admin only.");let db=fb.firestore(),usersSnap=await db.collection("users").get(),reqSnap=await db.collection("premiumRequests").get(),users=usersSnap.docs.map(d=>({uid:d.id,...d.data()})),requests=reqSnap.docs.map(d=>({uid:d.id,...d.data()}));renderAdminLists(users,requests,[],async uid=>{await db.collection("users").doc(uid).set({accountType:"premium",premiumStatus:"approved"},{merge:true});await db.collection("premiumRequests").doc(uid).delete()})}catch(err){$("#premiumRequests").innerHTML=`<p class="fine-print">${escapeHtml(err.message||"Admin data unavailable.")}</p>`}}
function renderAdminLists(users,requests,usage,approve){let pending=[...requests],pendingIds=new Set(pending.map(r=>r.uid||r.id));users.forEach(u=>{let uid=u.uid||u.id;if(uid&&!pendingIds.has(uid)&&u.premiumStatus==="requested"&&u.accountType!=="premium"){pending.push({...u,uid,status:"requested"});pendingIds.add(uid)}});$("#adminStats").innerHTML=stats([["Users",users.length],["Premium requests",pending.length],["Usage 24h",countUsage(usage,86400000)],["Usage 30d",countUsage(usage,2592000000)]]);$("#premiumRequests").innerHTML=pending.length?pending.map(r=>`<div class="history-row"><strong>${escapeHtml(r.email||"")}</strong><span>${escapeHtml(r.displayName||r.status||"requested")}</span><button class="soft" data-approve="${escapeHtml(r.uid||r.id)}">Approve</button></div>`).join(""):`<p class="fine-print">No pending requests.</p>`;$("#adminUsers").innerHTML=users.map(u=>{let uid=u.uid||u.id,needsApproval=u.premiumStatus==="requested"&&u.accountType!=="premium";return`<div class="history-row"><strong>${escapeHtml(u.email||"")}</strong><span>${escapeHtml(u.accountType||"basic")} آ· ${escapeHtml(u.premiumStatus||"none")}</span>${needsApproval?`<button class="soft" data-approve="${escapeHtml(uid)}">Approve</button>`:`<span>${u.lastLoginAt?.seconds?new Date(u.lastLoginAt.seconds*1000).toLocaleDateString():""}</span>`}</div>`}).join("");$$("[data-approve]").forEach(b=>b.onclick=async()=>{await approve(b.dataset.approve);toast("Premium approved.");renderAdmin()})}
function applyProfile(){let p=data.profile;document.documentElement.dataset.theme=p.theme||"lavender";$("#studentName").value=p.name||"";$("#voiceMode").value=p.voice||"bestie";$("#planLength").value=p.plan||"4";$("#themeSelect").value=p.theme||"lavender";$("#examMode").value=p.examMode||"adaptive";$("#topicSelect").value=p.topic||"Functions";$("#topicDifficulty").value=p.topicDifficulty||"Warm-up";$("#topicQuestionCount").value=p.topicQuestionCount||"10";$("#topicTestMinutes").value=p.topicTestMinutes||"30";updateSetupMode()}
