async function generatePracticeQuestions(mode,topic,difficulty,count){
  if(!functionsApi||!authUser){toast("AI questions need sign-in/Firebase. Using local backup for now.");return localQuestionFallback(mode,topic,difficulty,count)}
  try{
    toast("Generating OpenAI questionsâ€¦");
    let result=await callFn("generateQuestionsWithOpenAI",{mode,topic,difficulty,count,recentPrompts:(data.generatorLog.usedPromptTexts||[]).slice(-80)});
    let questions=(result.questions||[]).map((q,i)=>cleanAIQuestion(q,i,topic,difficulty,mode)).filter(questionHasFriendlyNumbers).slice(0,count);
    if(questions.length<count)questions.push(...localQuestionFallback(mode,topic,difficulty,count-questions.length));
    rememberQuestionSet(questions);
    toast(`OpenAI questions ready آ· ${result.model}`);
    return questions;
  }catch(error){
    console.warn("AI question fallback:",error);
    toast("OpenAI question generation is not ready, so I used the local backup.");
    return localQuestionFallback(mode,topic,difficulty,count);
  }
}
