function coachReply(q,text){
  let t=text.toLowerCase();
  if(/answer|walk.?through|solve it|full solution/.test(t)){exam.assisted??={};exam.assisted[q.id]=true;return`Letâ€™s walk through this exact question:\n\n${q.explanation}\n\nNow try explaining that last step in your own wordsâ€”thatâ€™s the part that makes it stick.`}
  if(/another|example|different number/.test(t))return`${COACH_EXAMPLES[q.topic]||q.lesson}\n\nTry copying those same steps on the current question.`;
  if(/formula|rule|equation/.test(t))return`${COACH_FORMULAS[q.topic]||q.lesson}\n\nThe important part is choosing the formula first, then substituting carefully.`;
  if(/first|start|hint|next step/.test(t))return`Start here: ${q.lesson}\n\nDo only the first substitution or factoring step before worrying about the final answer.`;
  if(/why|how come/.test(t))return`The reason is that each algebra step must keep both sides equivalent. For this problem: ${q.explanation}`;
  if(/simpl|confus|understand|what does|huh/.test(t))return`Super simple version: ${COACH_FORMULAS[q.topic]||q.lesson}\n\nThink of it as one small job at a time. ${COACH_EXAMPLES[q.topic]||""}`;
  if(/check|my answer|correct/.test(t))return`I can help you check the method without judging the final answer yet. Tell me what your first step was, then compare it with this hint: ${q.lesson}`;
  return`Iâ€™m an offline coach, so Iâ€™m best at questions about this ${q.topic} problem. Hereâ€™s the key idea: ${q.lesson}\n\nTry asking â€œexplain it simpler,â€‌ â€œshow another example,â€‌ â€œwhatâ€™s the first step?â€‌, or â€œwalk me through it.â€‌`;
}
function wantsFullCoachSolution(text){return /answer|walk.?through|solve it|full solution/.test(text.toLowerCase())}
function buildCoachPrompt(q,userText,messages){
  let recent=(messages||[]).slice(-8).map(m=>`${m.role==="bot"?"Tutor":"Student"}: ${m.text}`).join("\n");
  return `You are Honors Algebra 2 Prep's friendly math tutor for a student.
Explain clearly, step by step, in a kind beginner-friendly voice.
Do not shame the student. Keep the answer focused on Algebra 2.
If the student asks for the answer, you may walk through it, but emphasize understanding.
Use plain text, not LaTeX-heavy formatting.

Current problem:
Topic: ${q.topic}
Difficulty: ${q.difficulty}
Question: ${q.prompt}
Correct answer: ${Array.isArray(q.answer)?q.answer[0]:q.answer}
Built-in lesson: ${q.lesson}
Built-in explanation: ${q.explanation}

Recent chat:
${recent || "No prior chat yet."}

Student asks: ${userText}`;
}
async function realCoachReply(q,text,messages){
  if(!functionsApi||!authUser)return coachReply(q,text);
  try{
    let res=await callFn("generateWithOpenAI",{prompt:buildCoachPrompt(q,text,messages)});
    return (res?.outputText||"").trim()||coachReply(q,text);
  }catch(error){
    console.warn("AI coach fallback:",error);
    return `${coachReply(q,text)}\n\n(P.S. The real AI coach could not connect, so I used the offline backup.)`;
  }
}
